+            "Raw [bold] tag should appear literally (not parsed)"
+        );
+        assert!(
+            output.contains("[/]"),
+            "Raw [/] tag should appear literally (not parsed)"
+        );
+        assert!(
+            output.contains("Downloading"),
+            "Description text should be present"
